  INDEX `scan3_user_id`(`scan3_user_id` ASC) USING BTREE,
  INDEX `idx_medicine_id`(`medicine_id` ASC) USING BTREE,
  CONSTRAINT `medicine_trace_codes_ibfk_1` FOREIGN KEY (`medicine_id`) REFERENCES `medicines` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `medicine_trace_codes_ibfk_2` FOREIGN KEY (`scan1_user_id`) REFERENCES `users` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `medicine_trace_codes_ibfk_3` FOREIGN KEY (`scan2_user_id`) REFERENCES `users` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `medicine_trace_codes_ibfk_4` FOREIGN KEY (`scan3_user_id`) REFERENCES `users` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 7143 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = Dynamic;

